// Tier F — harvested Chromium editing scenarios.
//
// These fixtures were generated by tools/harvest-chromium.ts: the INPUT and
// operation sequence come from Chromium's web_tests/editing/ suite; the
// expected output.html is OUR editor's result (scenario-harvest mode, per
// vibe/Chrome_Editing_Tests_Adaptation.md). They lock in our behavior on real
// browser editing sequences and are additionally validated by the corpus-wide
// invert-roundtrip invariant.

import { describe, it, expect } from 'vitest'
import fs from 'node:fs'
import path from 'node:path'
import { fileURLToPath } from 'node:url'
import { findFixtureDirs, loadFixture, runFixtureCase } from '../helpers/fixture-runner.js'

const __dirname = path.dirname(fileURLToPath(import.meta.url))
const dirs = findFixtureDirs(__dirname)

function isFollowup(dir: string): boolean {
  const np = path.join(dir, 'NOTES.md')
  return fs.existsSync(np) && fs.readFileSync(np, 'utf8').includes('infrastructure follow-up')
}

describe('Tier F — harvested Chromium editing scenarios', () => {
  if (dirs.length === 0) {
    it.skip('no fixtures discovered', () => {})
    return
  }
  for (const dir of dirs) {
    const rel = path.relative(__dirname, dir)
    if (isFollowup(dir)) {
      it.skip(`${rel} (infrastructure follow-up)`, () => {})
      continue
    }
    it(rel, () => {
      const c = loadFixture(dir)
      const r = runFixtureCase(c)
      expect(r.actualDoc).toEqual(r.expectedDoc)
      if (r.invertRoundtrips !== null) expect(r.invertRoundtrips).toBe(true)
    })
  }
})
